// Builds the TipTap editor bundle for the native WebView.
//
//   bun run build:editor
//
// Bundles editor-webview-entry.js (@tiptap/core + starter-kit + marked) into a
// minified IIFE and writes it as a string export to lib/tiptapBundle.generated.ts,
// which lib/tiptapEditorHtml.ts inlines into the WebView HTML. Re-run after
// bumping @tiptap/* or marked. The generated file is committed so normal dev
// never needs this step.
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const here = path.dirname(fileURLToPath(import.meta.url))
const outFile = path.join(here, '..', 'lib', 'tiptapBundle.generated.ts')

const result = await Bun.build({
  entrypoints: [path.join(here, 'editor-webview-entry.js')],
  target: 'browser',
  format: 'iife',
  minify: true,
})

if (!result.success) {
  for (const log of result.logs) console.error(log)
  process.exit(1)
}

let code = await result.outputs[0].text()

// '</script' inside the bundle (only ever inside JS string/regex literals) would
// terminate the inline <script> block in the WebView HTML. '\/' === '/' in JS
// literals, so this escape is semantics-preserving.
code = code.replaceAll('</script', '<\\/script')

const banner =
  '// AUTO-GENERATED by scripts/build-editor-bundle.mjs — DO NOT EDIT.\n' +
  '// Rebuild with `bun run build:editor` after bumping @tiptap/* or marked.\n' +
  '// Minified IIFE that sets window.__SLATE_EDITOR__ = { Editor, StarterKit, marked }.\n' +
  '/* eslint-disable */\n'

await Bun.write(outFile, `${banner}export const TIPTAP_BUNDLE: string = ${JSON.stringify(code)}\n`)
console.log(`Wrote lib/tiptapBundle.generated.ts (${Math.round(code.length / 1024)} KB)`)
